#!/usr/bin/env python3\n\"\"\"\nRichManBot Launcher - Simple GUI to start the bot\nJust run: python launcher.py\n\"\"\"\n\nimport tkinter as tk\nfrom tkinter import ttk, messagebox\nimport subprocess\nimport sys\nimport os\nimport threading\nimport webbrowser\nfrom pathlib import Path\n\nclass RichManBotLauncher:\n    def __init__(self, root):\n        self.root = root\n        self.root.title(\"RichManBot Launcher 🤖\")\n        self.root.geometry(\"600x400\")\n        self.root.resizable(False, False)\n        \n        # Set background color\n        self.root.configure(bg='#1e1e2e')\n        \n        self.server_process = None\n        self.is_running = False\n        \n        self.setup_ui()\n        \n    def setup_ui(self):\n        \"\"\"Setup the user interface\"\"\"\n        \n        # Main frame with dark background\n        main_frame = tk.Frame(self.root, bg='#1e1e2e')\n        main_frame.pack(fill=tk.BOTH, expand=True, padx=20, pady=20)\n        \n        # Title\n        title_label = tk.Label(\n            main_frame,\n            text=\"🤖 RichManBot\",\n            font=(\"Arial\", 28, \"bold\"),\n            fg=\"#00d4ff\",\n            bg=\"#1e1e2e\"\n        )\n        title_label.pack(pady=10)\n        \n        # Subtitle\n        subtitle_label = tk.Label(\n            main_frame,\n            text=\"Professional Crypto Trading Dashboard\",\n            font=(\"Arial\", 12),\n            fg=\"#b0b0c3\",\n            bg=\"#1e1e2e\"\n        )\n        subtitle_label.pack(pady=5)\n        \n        # Status frame\n        status_frame = tk.Frame(main_frame, bg='#2d2d44', relief=tk.RIDGE, bd=1)\n        status_frame.pack(fill=tk.X, pady=20)\n        \n        status_label = tk.Label(\n            status_frame,\n            text=\"Status:\",\n            font=(\"Arial\", 11, \"bold\"),\n            fg=\"#ffffff\",\n            bg=\"#2d2d44\"\n        )\n        status_label.pack(side=tk.LEFT, padx=10, pady=10)\n        \n        self.status_text = tk.Label(\n            status_frame,\n            text=\"⚫ Stopped\",\n            font=(\"Arial\", 11, \"bold\"),\n            fg=\"#ff006e\",\n            bg=\"#2d2d44\"\n        )\n        self.status_text.pack(side=tk.LEFT, padx=10, pady=10)\n        \n        # Info text\n        info_text = tk.Label(\n            main_frame,\n            text=\"Click 'Start Bot' to launch the dashboard.\\nOnce started, your browser will open automatically.\",\n            font=(\"Arial\", 10),\n            fg=\"#b0b0c3\",\n            bg=\"#1e1e2e\",\n            justify=tk.CENTER\n        )\n        info_text.pack(pady=10)\n        \n        # Buttons frame\n        button_frame = tk.Frame(main_frame, bg='#1e1e2e')\n        button_frame.pack(fill=tk.X, pady=20)\n        \n        # Start button\n        self.start_btn = tk.Button(\n            button_frame,\n            text=\"🚀 Start Bot\",\n            font=(\"Arial\", 12, \"bold\"),\n            bg=\"#00ff41\",\n            fg=\"#000000\",\n            padx=20,\n            pady=10,\n            command=self.start_bot,\n            cursor=\"hand2\"\n        )\n        self.start_btn.pack(side=tk.LEFT, padx=5, expand=True, fill=tk.X)\n        \n        # Stop button\n        self.stop_btn = tk.Button(\n            button_frame,\n            text=\"🛑 Stop Bot\",\n            font=(\"Arial\", 12, \"bold\"),\n            bg=\"#ff006e\",\n            fg=\"#ffffff\",\n            padx=20,\n            pady=10,\n            command=self.stop_bot,\n            state=tk.DISABLED,\n            cursor=\"hand2\"\n        )\n        self.stop_btn.pack(side=tk.LEFT, padx=5, expand=True, fill=tk.X)\n        \n        # Open Browser button\n        self.open_btn = tk.Button(\n            button_frame,\n            text=\"🌐 Open Browser\",\n            font=(\"Arial\", 12, \"bold\"),\n            bg=\"#00d4ff\",\n            fg=\"#000000\",\n            padx=20,\n            pady=10,\n            command=self.open_browser,\n            state=tk.DISABLED,\n            cursor=\"hand2\"\n        )\n        self.open_btn.pack(side=tk.LEFT, padx=5, expand=True, fill=tk.X)\n        \n        # Log frame\n        log_label = tk.Label(\n            main_frame,\n            text=\"Server Log:\",\n            font=(\"Arial\", 10, \"bold\"),\n            fg=\"#ffffff\",\n            bg=\"#1e1e2e\"\n        )\n        log_label.pack(anchor=tk.W, pady=(10, 5))\n        \n        # Log text area\n        self.log_text = tk.Text(\n            main_frame,\n            height=8,\n            width=70,\n            bg=\"#2d2d44\",\n            fg=\"#00ff41\",\n            font=(\"Courier\", 9),\n            relief=tk.SUNKEN,\n            bd=1\n        )\n        self.log_text.pack(fill=tk.BOTH, expand=True)\n        \n        # Scrollbar for log\n        scrollbar = tk.Scrollbar(self.log_text)\n        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)\n        self.log_text.config(yscrollcommand=scrollbar.set)\n        scrollbar.config(command=self.log_text.yview)\n        \n        self.log(\"RichManBot Launcher Ready\")\n        self.log(\"Click 'Start Bot' to begin...\")\n        \n    def log(self, message):\n        \"\"\"Add message to log\"\"\"\n        self.log_text.insert(tk.END, f\"> {message}\\n\")\n        self.log_text.see(tk.END)\n        self.root.update()\n        \n    def start_bot(self):\n        \"\"\"Start the FastAPI server\"\"\"\n        self.log(\"Starting RichManBot...\")\n        \n        try:\n            # Check if dependencies are installed\n            self.log(\"Checking dependencies...\")\n            import fastapi\n            import uvicorn\n            self.log(\"✓ Dependencies found\")\n        except ImportError:\n            self.log(\"⚠ Installing dependencies (this may take a moment)...\")\n            try:\n                subprocess.run(\n                    [sys.executable, \"-m\", \"pip\", \"install\", \"-r\", \"requirements.txt\"],\n                    check=True,\n                    capture_output=True\n                )\n                self.log(\"✓ Dependencies installed\")\n            except subprocess.CalledProcessError as e:\n                self.log(f\"❌ Error installing dependencies: {e}\")\n                messagebox.showerror(\"Error\", \"Failed to install dependencies\")\n                return\n        \n        # Start the server in a separate thread\n        thread = threading.Thread(target=self._run_server, daemon=True)\n        thread.start()\n        \n        # Update UI\n        self.is_running = True\n        self.start_btn.config(state=tk.DISABLED)\n        self.stop_btn.config(state=tk.NORMAL)\n        self.open_btn.config(state=tk.NORMAL)\n        self.status_text.config(text=\"🟢 Running\", fg=\"#00ff41\")\n        self.log(\"✓ Bot started successfully!\")\n        self.log(\"Dashboard: http://localhost:8000/static/index.html\")\n        \n    def _run_server(self):\n        \"\"\"Run the FastAPI server\"\"\"\n        try:\n            self.server_process = subprocess.Popen(\n                [sys.executable, \"backend/main.py\"],\n                stdout=subprocess.PIPE,\n                stderr=subprocess.PIPE,\n                text=True,\n                bufsize=1\n            )\n            \n            # Read output\n            for line in self.server_process.stdout:\n                if line.strip():\n                    self.log(line.strip())\n                    \n        except Exception as e:\n            self.log(f\"❌ Error: {e}\")\n            self.is_running = False\n            self.start_btn.config(state=tk.NORMAL)\n            self.stop_btn.config(state=tk.DISABLED)\n            self.open_btn.config(state=tk.DISABLED)\n            self.status_text.config(text=\"⚫ Stopped\", fg=\"#ff006e\")\n            \n    def stop_bot(self):\n        \"\"\"Stop the FastAPI server\"\"\"\n        if self.server_process:\n            self.log(\"Stopping bot...\")\n            self.server_process.terminate()\n            try:\n                self.server_process.wait(timeout=5)\n            except subprocess.TimeoutExpired:\n                self.server_process.kill()\n            self.log(\"✓ Bot stopped\")\n        \n        # Update UI\n        self.is_running = False\n        self.start_btn.config(state=tk.NORMAL)\n        self.stop_btn.config(state=tk.DISABLED)\n        self.open_btn.config(state=tk.DISABLED)\n        self.status_text.config(text=\"⚫ Stopped\", fg=\"#ff006e\")\n        \n    def open_browser(self):\n        \"\"\"Open the dashboard in browser\"\"\"\n        self.log(\"Opening browser...\")\n        webbrowser.open(\"http://localhost:8000/static/index.html\")\n        \n    def on_closing(self):\n        \"\"\"Handle window close\"\"\"\n        if self.is_running:\n            if messagebox.askyesno(\"Exit\", \"Bot is still running. Stop it before closing?\"):\n                self.stop_bot()\n        self.root.destroy()\n\n\nif __name__ == \"__main__\":\n    root = tk.Tk()\n    app = RichManBotLauncher(root)\n    root.protocol(\"WM_DELETE_WINDOW\", app.on_closing)\n    root.mainloop()\n